    longestCommonPrefix(strs) {
        // Return empty string if input is empty
        if (strs.length === 0) return "";

        // Sort strings lexicographically
        strs.sort();

        // First string after sorting
        const first = strs[0];

        // Last string after sorting
        const last = strs[strs.length - 1];

        // To store the common prefix
        let commonPrefix = "";

        // Compare characters from both strings
        for (let i = 0; i < Math.min(first.length, last.length); i++) {
            // Stop if characters differ
            if (first[i] !== last[i]) {
                return commonPrefix;
            }
            // Add matching character to result
            commonPrefix += first[i];
        }

        // Return the final common prefix
        return commonPrefix;
    }
}

